# 输入获取
m, n = map(int, input().split())

children = {}
cap = {}

for _ in range(m):
    fa_id, fa_cap, ch_str = input().split()
    children[fa_id] = []
    cap[fa_id] = int(fa_cap)

    if len(ch_str) > 2:
        children[fa_id].extend(ch_str[1:-1].split(","))


# 算法入口
def getResult(target):
    ans = 0

    stack = [target]

    while len(stack) > 0:
        id = stack.pop()
        if cap.get(id) is None:
            continue
        ans += cap[id]
        stack.extend(children[id])

    return ans


# 算法调用
print(getResult(str(n)))
